class Solution {
public:
    string resultingString(string s) {
        vector<char> st;
        for (char c : s) {
            if (!st.empty()) {
                char prev = st.back();
                if ((c == 'a' && prev == 'z') || (c == 'z' && prev == 'a') ||
                    abs(c - prev) == 1) {
                    st.pop_back();
                    continue;
                }
            }
            st.push_back(c);
        }
        return string(st.begin(), st.end());
    }
};
```
